import asyncio
import json
from datetime import datetime
from typing import Dict, Set, Optional
from fastapi import FastAPI, WebSocket, WebSocketDisconnect
from fastapi.responses import HTMLResponse

app = FastAPI(title="WebSocket Chat API")

# ── Connection Manager ──────────────────────────────────
class ConnectionManager:
    def __init__(self):
        self.active_connections: Dict[str, Set[WebSocket]] = {}
        self.user_connections: Dict[WebSocket, str] = {}

    async def connect(self, websocket: WebSocket, room: str):
        await websocket.accept()
        if room not in self.active_connections:
            self.active_connections[room] = set()
        self.active_connections[room].add(websocket)
        self.user_connections[websocket] = room

        await self.broadcast(room, {
            "type": "system",
            "message": f"User joined {room}",
            "timestamp": datetime.now().isoformat(),
            "users": len(self.active_connections[room])
        })

    def disconnect(self, websocket: WebSocket):
        room = self.user_connections.pop(websocket, None)
        if room and room in self.active_connections:
            self.active_connections[room].discard(websocket)
            if not self.active_connections[room]:
                del self.active_connections[room]

    async def broadcast(self, room: str, message: dict):
        if room in self.active_connections:
            dead_connections = set()
            for connection in self.active_connections[room]:
                try:
                    await connection.send_json(message)
                except Exception:
                    dead_connections.add(connection)
            for conn in dead_connections:
                self.active_connections[room].discard(conn)

    async def send_personal(self, websocket: WebSocket, message: dict):
        try:
            await websocket.send_json(message)
        except Exception:
            pass

manager = ConnectionManager()


# ── HTML Client ─────────────────────────────────────────
HTML_CLIENT = """
<!DOCTYPE html>
<html>
<head><title>WebSocket Chat</title></head>
<body>
  <h1>WebSocket Chat</h1>
  <div id="messages"></div>
  <input type="text" id="messageInput" placeholder="Type a message...">
  <button onclick="sendMessage()">Send</button>
  <script>
    const room = 'general';
    const ws = new WebSocket(`ws://localhost:8000/ws/${room}`);
    const messagesDiv = document.getElementById('messages');

    ws.onmessage = function(event) {
      const data = JSON.parse(event.data);
      const msgDiv = document.createElement('div');
      msgDiv.textContent = `[${data.type}] ${data.message || data.content}`;
      messagesDiv.appendChild(msgDiv);
    };

    function sendMessage() {
      const input = document.getElementById('messageInput');
      ws.send(JSON.stringify({
        type: 'chat',
        content: input.value
      }));
      input.value = '';
    }
  </script>
</body>
</html>
"""


@app.get("/")
async def get():
    return HTMLResponse(HTML_CLIENT)


@app.websocket("/ws/{room}")
async def websocket_endpoint(websocket: WebSocket, room: str):
    await manager.connect(websocket, room)
    try:
        while True:
            data = await websocket.receive_json()

            message = {
                "type": "chat",
                "content": data.get("content", ""),
                "timestamp": datetime.now().isoformat(),
                "room": room
            }

            await manager.broadcast(room, message)
    except WebSocketDisconnect:
        manager.disconnect(websocket)
        await manager.broadcast(room, {
            "type": "system",
            "message": "User left the room",
            "timestamp": datetime.now().isoformat()
        })


# ── REST endpoints for WebSocket management ─────────────
@app.get("/rooms")
async def list_rooms():
    return {
        "rooms": [
            {"name": room, "users": len(connections)}
            for room, connections in manager.active_connections.items()
        ]
    }


@app.get("/rooms/{room}/users")
async def room_users(room: str):
    count = len(manager.active_connections.get(room, set()))
    return {"room": room, "users": count}
